INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (107611, 1, 0, "シズルさまにエリコさま、\nどうかされたのですか？", 0.5, 905, 0, 0, 19050041, 11, 10);
