INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (122511, 1, 0, "むっ…なんだ？\nこの獲物を狙う猛禽のような殺気は？\n誰かいるのか？", 0.5, 943, 0, 0, 19430038, 11, 5);
