INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (107911, 1, 0, "はい、そこの流れてくるおねーさん\nたい焼きいかがかにゃ？", 1, 944, 0, 0, 19440025, 11, 8);
