INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (107911, 1, 0, "なんだ、ユカリだったかにゃ。\n何ってもちろん商売にゃ！", 1, 944, 0, 0, 19440033, 11, 10);
